#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Define structure for data points
typedef struct {
 double x;
 double y;
} Point;

// Define k-means clustering function
void kmeans(Point* points, int n, int k) {
 // Initialize centroids randomly
 Point centroids[k];
 for (int i = 0; i < k; i++) {
 centroids[i].x = points[i].x;
 centroids[i].y = points[i].y;
 }

 // Iterate until convergence
 while (1) {
 // Assign points to clusters
 int clusters[n];
 for (int i = 0; i < n; i++) {
 double min_dist = INFINITY;
 int cluster = -1;
 for (int j = 0; j < k; j++) {
 double dist = sqrt(pow(points[i].x - centroids[j].x, 2) + pow(points[i].y - centroids[j].y, 2));
 if (dist < min_dist) {
 min_dist = dist;
 cluster = j;
 }
 }
 clusters[i] = cluster;
 }

 // Update centroids
 for (int i = 0; i < k; i++) {
 double sum_x = 0;
 double sum_y = 0;
 int count = 0;
 for (int j = 0; j < n; j++) {
 if (clusters[j] == i) {
 sum_x += points[j].x;
 sum_y += points[j].y;
 count++;
 }
 }
 centroids[i].x = sum_x / count;
 centroids[i].y = sum_y / count;
 }
 }
}
